window.HK2_LC3 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She is glancing toward a coworker.", "She is removing eyeglasses from her face.", "She is working near a sewing machine.", "She is putting a watch on a workstation."], "optko": ["그녀는 동료 쪽을 힐끗 보고 있다.", "그녀는 얼굴에서 안경을 벗고 있다.", "그녀는 재봉틀 근처에서 일하고 있다.", "그녀는 작업 공간에 시계를 놓고 있다."], "ans": 2, "audio": "Test03_01.mp3", "img": "hk2_t3_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["One of the men is leaning over in his seat.", "There are pants folded on a stool.", "One of the men is adjusting his hat.", "There are some chairs stacked along a wall."], "optko": ["남자들 중 한 명이 자리에서 몸을 구부리고 있다.", "의자 위에 개어진 바지들이 있다.", "남자들 중 한 명이 모자를 단정히 하고 있다.", "몇몇 의자들이 벽을 따라 쌓여 있다."], "ans": 0, "audio": "Test03_02.mp3", "img": "hk2_t3_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Cars are heading in various directions.", "Some city structures are being built.", "Bikes are propped against a railing.", "A cyclist is riding on a street."], "optko": ["차들이 다양한 방향으로 향하고 있다.", "도시 건축물들이 지어지고 있다.", "자전거들이 난간에 기대어져 있다.", "자전거를 탄 사람이 도로 위를 달리고 있다."], "ans": 3, "audio": "Test03_03.mp3", "img": "hk2_t3_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["The bag is being filled with leaves.", "Pumpkins have been set on a table.", "A rake is being used in a garden.", "Lawn furniture is situated by a home."], "optko": ["포대가 나뭇잎으로 채워지고 있다.", "호박들이 탁자 위에 놓여 있다.", "갈퀴가 정원에서 사용되고 있다.", "정원용 가구가 집 옆에 위치해 있다."], "ans": 1, "audio": "Test03_04.mp3", "img": "hk2_t3_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["A menu is being handed to a customer.", "One man has crossed his arms.", "The table has been cleared of cups.", "One woman is holding a device."], "optko": ["메뉴가 손님에게 건네지고 있다.", "한 남자가 팔짱을 꼈다.", "식탁에 컵들이 치워져 있다.", "한 여자가 기기를 들고 있다."], "ans": 3, "audio": "Test03_05.mp3", "img": "hk2_t3_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A piece of luggage is being unzipped.", "A man is buttoning up a dress shirt.", "A potted plant is standing next to the closet.", "A man is twisting a belt into a coil."], "optko": ["여행 가방 하나의 지퍼가 열리고 있다.", "한 남자가 정장 셔츠의 단추를 채우고 있다.", "화분에 심은 식물이 옷장 옆에 있다.", "한 남자가 벨트를 고리 모양으로 감고 있다."], "ans": 2, "audio": "Test03_06.mp3", "img": "hk2_t3_q6.jpg"}, {"n": 7, "part": 2, "q": "What food do you want to eat for dinner tonight?", "qko": "오늘 저녁 식사로 어떤 음식을 드시고 싶으세요?", "opts": ["Something spicy.", "He usually eats pizza on Tuesdays.", "Yes, I like that restaurant."], "optko": ["매운 거요.", "그는 화요일마다 주로 피자를 먹어요.", "네, 저는 그 식당을 좋아해요."], "ans": 0, "audio": "Test03_07.mp3"}, {"n": 8, "part": 2, "q": "Could you please e-mail me the analysis?", "qko": "분석 결과를 저에게 이메일로 보내주실 수 있나요?", "opts": ["Can I send it in an hour?", "Because it's not finished yet.", "Only twelve pages."], "optko": ["그것을 한 시간 후에 보내드려도 될까요?", "그것이 아직 완료되지 않았기 때문이에요.", "단 열두 장이요."], "ans": 0, "audio": "Test03_08.mp3"}, {"n": 9, "part": 2, "q": "Who owns that blue minivan parked across the street?", "qko": "길 건너에 주차되어 있는 저 파란색 미니밴을 누가 소유하나요?", "opts": ["Parking is free on weekends.", "From the motor show last month.", "That would be me."], "optko": ["주말에는 주차가 무료예요.", "지난달의 자동차 쇼로부터요.", "저일 거예요."], "ans": 2, "audio": "Test03_09.mp3"}, {"n": 10, "part": 2, "q": "When is the press conference going to get underway?", "qko": "기자 회견은 언제 시작할 건가요?", "opts": ["Once the mayor arrives.", "The deadline was yesterday.", "In the building's central lobby."], "optko": ["시장이 도착하면요.", "마감 일자는 어제였어요.", "건물 중앙 로비에서요."], "ans": 0, "audio": "Test03_10.mp3"}, {"n": 11, "part": 2, "q": "Would you like to go to the international film festival with me?", "qko": "저와 함께 국제 영화제에 가실래요?", "opts": ["The tickets are 30 dollars per day.", "I can't, unless I finish my project early.", "The movie's subtitles weren't very accurate or natural."], "optko": ["티켓은 하루당 30달러예요.", "제가 프로젝트를 일찍 끝내지 않는 한, 갈 수 없어요.", "그 영화의 자막은 그다지 정확하거나 자연스럽지 않았어요."], "ans": 1, "audio": "Test03_11.mp3"}, {"n": 12, "part": 2, "q": "Which television program will the CEO be appearing on this evening?", "qko": "오늘 저녁에 최고 경영자가 어느 텔레비전 프로그램에 출연할까요?", "opts": ["I prefer listening to the radio to watching TV.", "It's called Finance Today.", "I think the topic is very appealing."], "optko": ["저는 TV를 보는 것보다 라디오를 듣는 것을 더 좋아해요.", "그것은 Finance Today라고 해요.", "저는 그 주제가 매우 흥미롭다고 생각해요."], "ans": 1, "audio": "Test03_12.mp3"}, {"n": 13, "part": 2, "q": "The C34 tablet is scheduled to launch in June.", "qko": "C34 태블릿 컴퓨터가 6월에 출시될 예정이에요.", "opts": ["Can their appointment be rescheduled?", "She will fix my computer today.", "I believe it will be very popular."], "optko": ["그들의 예약 일정이 변경될 수 있나요?", "그녀가 오늘 제 컴퓨터를 고쳐줄 거예요.", "그것은 매우 인기 있을 거라고 생각해요."], "ans": 2, "audio": "Test03_13.mp3"}, {"n": 14, "part": 2, "q": "Did the technical assistant ever meet with you?", "qko": "기술 보조가 당신과 만난 적이 있나요?", "opts": ["Some technical support.", "Sure, I'll help you.", "Not yet."], "optko": ["몇 가지 기술적 도움이요.", "물론이죠, 제가 도와드릴게요.", "아직이요."], "ans": 2, "audio": "Test03_14.mp3"}, {"n": 15, "part": 2, "q": "Isn't Alice transferring to the New Orleans branch?", "qko": "Alice는 뉴올리언스 지사로 전근 가지 않나요?", "opts": ["That's what I've heard.", "She knows his extension number.", "Yes, I'd appreciate that."], "optko": ["저는 그렇게 들었어요.", "그녀가 그의 내선 번호를 알고 있어요.", "네, 그렇게 해주시면 감사할 것 같아요."], "ans": 0, "audio": "Test03_15.mp3"}, {"n": 16, "part": 2, "q": "When is our connecting flight going to begin boarding?", "qko": "우리의 연결 항공편은 언제 탑승을 시작할 건가요?", "opts": ["I'll inform the board members.", "We left it at the gate.", "At 11:45 A.M."], "optko": ["제가 이사회 임원들에게 알릴게요.", "우리가 그걸 게이트에 두었어요.", "오전 11시 45분에요."], "ans": 2, "audio": "Test03_16.mp3"}, {"n": 17, "part": 2, "q": "You finished writing your speech for the shareholders meeting, didn't you?", "qko": "당신은 주주 총회를 위한 연설문 작성을 끝냈죠, 안 그런가요?", "opts": ["I still need to revise it.", "I'm not sure everyone heard me.", "He's giving a speech this year."], "optko": ["아직 그것을 수정해야 해요.", "다들 제 말을 들었는지 모르겠어요.", "그가 올해 연설을 할 거예요."], "ans": 0, "audio": "Test03_17.mp3"}, {"n": 18, "part": 2, "q": "Are Patrick and Dennis coming to the company fundraiser?", "qko": "Patrick과 Dennis가 회사 자선 모금 행사에 올 건가요?", "opts": ["No, they haven't gotten a receipt.", "It's unlikely, since they're busy planning another event.", "I think they're getting raises."], "optko": ["아니요, 그들은 영수증을 받지 않았어요.", "그럴 것 같지 않아요, 그들은 다른 행사를 계획하느라 바쁘거든요.", "그들은 임금 인상을 받을 것 같아요."], "ans": 1, "audio": "Test03_18.mp3"}, {"n": 19, "part": 2, "q": "Who is in charge of the hiring process for the new sales manager?", "qko": "누가 새로운 영업 부장의 채용 과정을 담당하고 있나요?", "opts": ["Ms. Foster expected a much higher price.", "It hasn't been decided yet.", "Your application has been approved."], "optko": ["Ms. Foster는 훨씬 더 높은 가격을 기대했어요.", "아직 결정되지 않았어요.", "당신의 신청서가 승인되었어요."], "ans": 1, "audio": "Test03_19.mp3"}, {"n": 20, "part": 2, "q": "Will Jeff be going to the annual artists' convention in Seattle?", "qko": "Jeff가 시애틀의 연례 예술가 협의회에 갈 건가요?", "opts": ["It's at the Belleville Hall.", "The presentation was very informative.", "No, not this year."], "optko": ["그것은 Belleville 홀에 있어요.", "발표는 매우 유익했어요.", "아니요, 올해는 아니에요."], "ans": 2, "audio": "Test03_20.mp3"}, {"n": 21, "part": 2, "q": "There seems to be something wrong with the printer.", "qko": "프린터에 무슨 문제가 있는 것 같아요.", "opts": ["No, it's over there in the corner.", "I'll take a look at it.", "I have the document."], "optko": ["아니요, 그건 저기 구석에 있어요.", "제가 그것을 한번 볼게요.", "제가 그 서류를 가지고 있어요."], "ans": 1, "audio": "Test03_21.mp3"}, {"n": 22, "part": 2, "q": "Where is the best place to buy a suit and tie for my job interview next week?", "qko": "다음 주의 제 구직 면접을 위한 정장과 넥타이를 사기에 가장 적합한 장소는 어디인가요?", "opts": ["For a graduation ceremony tomorrow.", "There's a store on East Street.", "That one looks really great on you."], "optko": ["내일 졸업식을 위해서요.", "East가에 상점이 있어요.", "그것은 당신에게 정말 잘 어울려요."], "ans": 1, "audio": "Test03_22.mp3"}, {"n": 23, "part": 2, "q": "Why is Dr. Flanders late for my appointment?", "qko": "Dr. Flanders는 왜 저의 예약에 늦는 건가요?", "opts": ["He is examining another patient.", "After I complete medical school.", "Sorry, I'll be late for the meeting."], "optko": ["그는 다른 환자를 진찰하고 있어요.", "제가 의과 대학을 끝마치고 난 후에요.", "죄송해요, 저는 회의에 늦을 거예요."], "ans": 0, "audio": "Test03_23.mp3"}, {"n": 24, "part": 2, "q": "How long have you had your cell phone?", "qko": "당신은 휴대 전화를 얼마나 오래 가지고 있었나요?", "opts": ["I got a call from my manager.", "Yes, I've lived here for a long time.", "I purchased it earlier this year."], "optko": ["저는 부장님으로부터 전화를 받았어요.", "네, 저는 이곳에 오랫동안 살았어요.", "올해 초에 구매했어요."], "ans": 2, "audio": "Test03_24.mp3"}, {"n": 25, "part": 2, "q": "Are you still searching for a gym, or have you found one you like?", "qko": "당신은 아직 체육관을 찾고 있나요, 아니면 마음에 드는 곳을 찾았나요?", "opts": ["Both options sound great.", "I gained 10 kilograms since last year.", "Unfortunately, I'm still looking."], "optko": ["두 가지 선택 사항이 모두 좋아 보이네요.", "저는 지난해 이래로 10킬로그램이 쪘어요.", "안타깝게도, 저는 아직 찾고 있어요."], "ans": 2, "audio": "Test03_25.mp3"}, {"n": 26, "part": 2, "q": "When will the holiday party take place?", "qko": "휴일 파티는 언제 개최될 건가요?", "opts": ["It's going to be quite a celebration.", "The last week of December.", "At a hotel near our office."], "optko": ["대단한 기념행사가 될 거예요.", "12월 마지막 주요.", "우리 사무실 근처 호텔에서요."], "ans": 1, "audio": "Test03_26.mp3"}, {"n": 27, "part": 2, "q": "Where are the blueprints for the shopping center we're designing?", "qko": "우리가 설계 중인 쇼핑센터의 청사진들은 어디에 있나요?", "opts": ["Actually, it's from an online shopping mall.", "I agree with your plan.", "One of the other architects might know."], "optko": ["사실, 그것은 온라인 쇼핑몰에서 산 거예요.", "저는 당신의 계획에 동의해요.", "다른 건축가들 중 한 명이 알 수도 있어요."], "ans": 2, "audio": "Test03_27.mp3"}, {"n": 28, "part": 2, "q": "I just noticed that my passport will expire at the beginning of February.", "qko": "2월 초에 제 여권이 만료될 거라는 것을 방금 알았어요.", "opts": ["Make sure you renew it before you go to Spain.", "It's located just past the courthouse.", "She arrived in Virginia in January."], "optko": ["스페인에 가기 전에 반드시 그것을 갱신하세요.", "그곳은 법원을 지나서 바로 위치해 있어요.", "그녀는 1월에 버지니아에 도착했어요."], "ans": 0, "audio": "Test03_28.mp3"}, {"n": 29, "part": 2, "q": "Weren't customers notified about the increase in subscription rates?", "qko": "고객들이 구독료 인상에 대해 통보받지 않았나요?", "opts": ["Sales decreased by over 10 percent.", "I'm curious about that as well.", "This is the latest edition."], "optko": ["매출이 10퍼센트 넘게 감소했어요.", "저도 그게 궁금해요.", "이것이 가장 최신판이에요."], "ans": 1, "audio": "Test03_29.mp3"}, {"n": 30, "part": 2, "q": "What made you decide to become a veterinarian?", "qko": "무엇이 당신이 수의사가 되기로 결정하게 만들었나요?", "opts": ["I would like to be a doctor.", "I love working with animals.", "It took about eight years."], "optko": ["저는 의사가 되고 싶어요.", "저는 동물들과 일하는 것을 좋아해요.", "약 8년이 걸렸어요."], "ans": 1, "audio": "Test03_30.mp3"}, {"n": 31, "part": 2, "q": "But I thought the sketches for the new fashion line were finished.", "qko": "하지만 전 새로운 패션 제품을 위한 밑그림이 완성되었을 거라고 생각했어요.", "opts": ["Try them on before making a decision.", "We've been selling them for quite a while.", "Well, they'll be done tomorrow."], "optko": ["결정하기 전에 그것들을 입어보세요.", "우린 그것들을 꽤 오랫동안 판매해 왔어요.", "음, 그것들은 내일 완료될 거예요."], "ans": 2, "audio": "Test03_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test03_32-34.mp3", "qs": [{"n": 32, "q": "Where most likely does the woman work?", "opts": ["At a frame shop", "At a camera factory", "At a photography studio", "At an art gallery"], "ans": 0, "ko": "여자는 어디에서 일하는 것 같은가?"}, {"n": 33, "q": "What is the problem?", "opts": ["A photograph is damaged.", "A service is no longer offered.", "A picture has been misplaced.", "An item is not ready."], "ans": 3, "ko": "무엇이 문제인가?"}, {"n": 34, "q": "When will the man most likely visit the business?", "opts": ["This afternoon", "Tomorrow morning", "Tomorrow evening", "Next week"], "ans": 2, "ko": "남자는 언제 업체를 방문할 것 같은가?"}], "script": [{"sp": "W", "en": "Thank you for calling Palmer and Sons. How can I help you?", "ko": "Palmer and Sons에 전화주셔서 감사합니다. 어떻게 도와드릴까요?"}, {"sp": "M", "en": "My name is Brent Miller, and I placed an order late last week to have a custom frame made for a picture I took. I'm wondering if I can come pick it up this afternoon.", "ko": "제 이름은 Brent Miller이고, 제가 찍은 사진을 위해 맞춤 액자를 제작하려고 지난주 후반에 주문을 했어요. 오늘 오후에 그것을 가지러 갈 수 있을지 궁금해요."}, {"sp": "W", "en": "Unfortunately not, Mr. Miller. I'm running behind schedule, so I've had to postpone working on your order until tomorrow afternoon. I apologize for the inconvenience.", "ko": "유감스럽지만 안 되겠어요, Mr. Miller. 제가 일정이 늦어져서, 귀하의 주문품을 작업하는 것을 내일 오후까지로 미뤄야만 했어요. 불편에 대해 사과드립니다."}, {"sp": "M", "en": "That's OK. I don't need it until next week, so tomorrow is fine. I can stop by on my way home from work in the evening.", "ko": "괜찮아요. 다음 주나 되어야 필요한 거라서, 내일도 괜찮아요. 제가 저녁에 회사에서 집으로 가는 길에 들를 수 있어요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test03_35-37.mp3", "qs": [{"n": 35, "q": "Who most likely is the man?", "opts": ["A designer", "A repairperson", "A salesperson", "An event planner"], "ans": 2, "ko": "남자는 누구인 것 같은가?"}, {"n": 36, "q": "What does the woman want to do?", "opts": ["Fix a speaker", "Extend a warranty", "Return a device", "Select a present"], "ans": 3, "ko": "여자는 무엇을 하고 싶어 하는가?"}, {"n": 37, "q": "What is mentioned about the Tide EX?", "opts": ["It will not be released for a month.", "It is temporarily out of stock.", "It can be used without a cable.", "It comes with a free case."], "ans": 2, "ko": "Tide EX에 관해 무엇이 언급되는가?"}], "script": [{"sp": "M", "en": "I see that you're looking at our store's newest collection of speakers. Do you have any questions about the products? If so, I'd be happy to answer them.", "ko": "고객님께서 저희 가게의 최신 스피커 컬렉션을 살펴보고 계신 것 같네요. 제품들에 관해 질문이 있으신가요? 만약 있으시다면, 제가 기꺼이 답변해 드리겠습니다."}, {"sp": "W", "en": "I'm interested in buying a speaker for my friend as a gift. He wants a portable one to connect to his cell phone. Do you have something matching that description?", "ko": "제 친구를 위한 선물로 스피커를 사는 데 관심이 있어요. 그는 휴대 전화에 연결할 수 있는 휴대용 스피커를 원해요. 이 설명에 맞는 것이 있나요?"}, {"sp": "M", "en": "I recommend the Tide EX. It's designed specifically for cell phones. It's lightweight and even has wireless capabilities. Plus, we are offering it at 10 percent off the regular price this week.", "ko": "Tide EX를 추천해 드립니다. 그것은 휴대 전화를 위해 특별히 디자인되었어요. 그것은 가볍고 심지어는 무선 기능도 있습니다. 게다가, 저희가 이번 주에 정가에서 10퍼센트 할인을 제공해 드리고 있어요."}, {"sp": "W", "en": "Thanks for the suggestion. I'll go and take a look at it now.", "ko": "추천해 주셔서 감사해요. 지금 가서 그것을 살펴볼게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test03_38-40.mp3", "qs": [{"n": 38, "q": "What is the purpose of the call?", "opts": ["To make a job offer", "To confirm an appointment", "To discuss a replacement", "To change an interview date"], "ans": 2, "ko": "전화의 목적은 무엇인가?"}, {"n": 39, "q": "Who most likely is Richard Hammel?", "opts": ["A local politician", "A copywriter", "A conference organizer", "A magazine editor"], "ans": 1, "ko": "Richard Hammel은 누구인 것 같은가?"}, {"n": 40, "q": "What does the woman ask the man to do?", "opts": ["Call a potential candidate", "Write an advertisement", "Look through applications", "Take part in a conversation"], "ans": 3, "ko": "여자는 남자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "W", "en": "Hello, Hans. This is Karen. As you already know, Jim Bates is stepping down as head copywriter at the end of this month. That means we'll have to move someone into his position. Who do you think would be a good candidate?", "ko": "안녕하세요, Hans. 저는 Karen이에요. 당신도 이미 아시다시피, Jim Bates가 이번 달 말에 수석 광고 문안 작성자 직에서 사임할 거예요. 그건 우리가 그의 자리로 누군가를 보내야 할 것임을 의미해요. 누가 괜찮은 후보자가 될 거라고 생각하시나요?"}, {"sp": "M", "en": "Personally, I'm in favor of Richard Hammel. He's been a dedicated employee for 10 years. He's written the text for a variety of advertisements for us and seems to understand all aspects of the job. What do you think?", "ko": "개인적으로 저는 Richard Hammel을 지지해요. 그는 10년 동안 헌신적인 직원이었어요. 그는 우리를 위해 다양한 광고들의 원고를 썼고 이 일의 모든 측면들을 이해하는 것 같아요. 어떻게 생각하시나요?"}, {"sp": "W", "en": "I have several candidates in mind. Hammel is one of them. Can you meet me in the conference room in two hours? I'd like to talk about this matter further.", "ko": "저는 몇몇 후보자들을 염두에 두고 있어요. Hammel은 그들 중 한 명이에요. 두 시간 후에 회의실에서 저와 만날 수 있나요? 이 문제에 관해 더 이야기를 나누고 싶어요."}, {"sp": "M", "en": "Sure thing. See you then.", "ko": "그럼요. 그때 봐요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음 → 미국식 발음", "audio": "Test03_41-43.mp3", "qs": [{"n": 41, "q": "Where most likely does the man work?", "opts": ["At a city tourism office", "At an accommodation facility", "At a travel agency", "At a community center"], "ans": 1, "ko": "남자는 어디에서 일하는 것 같은가?"}, {"n": 42, "q": "What does the man mean when he says, \"Molly Branson is our activities manager\"?", "opts": ["He did not make a reservation.", "He cannot find some information.", "He did not organize an activity.", "He cannot fulfill a request."], "ans": 3, "ko": "남자는 \"Molly Branson이 저희의 활동 관리자입니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 43, "q": "What is indicated in the brochure?", "opts": ["Departure times", "Membership benefits", "Excursion rates", "Hiking destinations"], "ans": 0, "ko": "소책자에는 무엇이 명시되어 있는가?"}], "script": [{"sp": "W1", "en": "This is Emily Baker in Suite 324. I'd like to book one of the excursions listed in the resort's guest guide. Can you do that for me?", "ko": "저는 스위트룸 324호의 Emily Baker입니다. 리조트의 투숙객 가이드에 실려 있는 여행들 중 하나를 예약하고 싶은데요. 저를 위해 그것을 해주실 수 있나요?"}, {"sp": "M", "en": "Molly Branson is our activities manager. I'll transfer you to her now.", "ko": "Molly Branson이 저희의 활동 관리자입니다. 지금 그녀에게 전화를 돌려드리겠습니다."}, {"sp": "W1", "en": "No problem.", "ko": "그래요."}, {"sp": "W2", "en": "Hello, Ms. Baker. I'm Molly. Brian says you'd like to join an excursion. We offer a great variety of options such as tours of historic Holston City, guided hikes, and fishing trips.", "ko": "안녕하세요, Ms. Baker. 저는 Molly입니다. Brian이 고객님께서 여행에 참가하고 싶어 하신다고 말했어요. 저희는 역사적으로 중요한 Holston시 관광, 가이드가 안내하는 도보 여행, 그리고 낚시 관광과 같은 매우 다양한 선택 사항들을 제공합니다."}, {"sp": "W1", "en": "I'm interested in the Holston City tour. However, while your brochure says groups leave daily at 9 A.M., nothing is mentioned about when they return.", "ko": "저는 Holston시 관광에 관심이 있어요. 하지만, 귀사의 소책자에 매일 오전 9시에 그룹이 출발한다고 쓰여있는 반면, 언제 돌아오는지에 관해서는 아무것도 언급되어 있지 않아요."}, {"sp": "W2", "en": "They get back around 3 P.M.", "ko": "그룹은 오후 3시쯤에 돌아옵니다."}, {"sp": "W1", "en": "Perfect. Can you sign me up for tomorrow?", "ko": "완벽하네요. 저를 내일로 등록해 주시겠어요?"}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test03_44-46.mp3", "qs": [{"n": 44, "q": "Who most likely is the man?", "opts": ["A division head", "A documentary filmmaker", "A Web site manager", "A personal secretary"], "ans": 0, "ko": "남자는 누구인 것 같은가?"}, {"n": 45, "q": "What did the woman do last year?", "opts": ["Implemented new regulations", "Moved to another department", "Purchased instructional materials", "Managed a construction project"], "ans": 2, "ko": "여자는 작년에 무엇을 했는가?"}, {"n": 46, "q": "How will the woman share the files?", "opts": ["By uploading them to a site", "By attaching them to an e-mail", "By placing them on a USB disk", "By copying them to a computer"], "ans": 0, "ko": "여자는 파일들을 어떻게 공유할 것인가?"}], "script": [{"sp": "M", "en": "Now that I'm in charge of the company's occupational safety department, I've got to give a safety seminar to some of our construction workers. Do we have any instructional videos that I can use?", "ko": "제가 회사의 직업 안전 부서를 관리하고 있으므로, 우리의 몇몇 공사장 인부들에게 안전 세미나를 해주어야 해요. 제가 사용할 수 있는 교육용 비디오들이 있나요?"}, {"sp": "W", "en": "Quite a few. What type of video do you want to show?", "ko": "꽤 많이 있어요. 어떤 종류의 비디오를 보여주고 싶으신 건가요?"}, {"sp": "M", "en": "One featuring precautionary measures at building sites.", "ko": "건설 현장에서의 예방책을 포함하는 비디오요."}, {"sp": "W", "en": "Oh, yeah. I bought a series of training videos last year. One of them deals with that topic.", "ko": "아, 네. 제가 작년에 일련의 교육 비디오들을 구입했어요. 그것들 중 하나가 그 주제를 다뤄요."}, {"sp": "M", "en": "It'd be great if you could send that one to me soon.", "ko": "제게 그것을 곧 보내주시면 좋겠어요."}, {"sp": "W", "en": "They're on my work computer, but the files are too large to e-mail. So I'll post them on our online board for you to access.", "ko": "제 업무용 컴퓨터에 있는데, 파일들이 이메일로 보내기에는 너무 커요. 그러니 당신이 접근할 수 있도록 우리 온라인 게시판에 올릴게요."}, {"sp": "M", "en": "That works for me.", "ko": "좋아요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test03_47-49.mp3", "qs": [{"n": 47, "q": "Why is the woman calling?", "opts": ["To arrange for an apartment showing", "To check the status of a rental space", "To change an upcoming meeting date", "To inquire about accommodation options"], "ans": 1, "ko": "여자는 왜 전화를 하고 있는가?"}, {"n": 48, "q": "According to the man, why has a task been delayed?", "opts": ["A crew of workers is progressing slowly.", "An employee made an incorrect purchase.", "Some units are still under construction.", "A tenant has canceled a lease."], "ans": 1, "ko": "남자에 따르면, 작업은 왜 지연되었는가?"}, {"n": 49, "q": "What does the man say about the apartment?", "opts": ["It has been vacant for two months.", "It will be painted multiple colors.", "It currently has an occupant.", "It will be ready in a few days."], "ans": 3, "ko": "남자는 아파트에 관해 무엇을 말하는가?"}], "script": [{"sp": "W", "en": "Cliff, it's Rita calling from Shine Realty. Has Unit 219 been cleaned and repainted yet in preparation for the new renters?", "ko": "Cliff, 저는 Shine 부동산에서 전화드리는 Rita입니다. 219호가 이제 새로운 세입자들에 대비하여 청소되고 다시 페인트칠 되었나요?"}, {"sp": "M", "en": "I'm afraid it hasn't. The property has been thoroughly cleaned, but one of our painters accidentally bought the wrong paint color. So, they aren't able to paint the apartment yet.", "ko": "유감스럽지만 안 되었어요. 건물이 완전히 청소되었지만, 우리 페인트공들 중 한 명이 실수로 엉뚱한 색의 페인트를 샀어요. 그래서, 그들은 아직 아파트를 페인트칠할 수 없어요."}, {"sp": "W", "en": "Well, the new tenants are moving in on April 1, which is only five days away. It's essential that everything be taken care of before then.", "ko": "음, 새로운 세입자들은 4월 1일에 이사 올 건데, 겨우 5일밖에 남지 않았어요. 모든 것이 그전에 처리되는 것이 필수적이에요."}, {"sp": "M", "en": "I spoke to the head painter this morning, and he assured me the apartment would be fully ready within the next three days. There shouldn't be anything to worry about.", "ko": "오늘 아침에 페인트공 책임자와 이야기했고, 그는 아파트가 앞으로 3일 이내에 완전히 준비될 것이라고 장담했어요. 걱정할 건 아무것도 없을 거예요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test03_50-52.mp3", "qs": [{"n": 50, "q": "Where do the speakers most likely work?", "opts": ["At an online marketing agency", "At an environmental organization", "At a light bulb manufacturer", "At an electric utility company"], "ans": 2, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 51, "q": "Why does the woman reject the man's first slogan idea?", "opts": ["It is not particularly memorable.", "It uses overly complex wording.", "It could be considered offensive.", "It lacks the proper emphasis."], "ans": 3, "ko": "여자는 왜 남자의 첫 번째 선전 문구 아이디어를 거절하는가?"}, {"n": 52, "q": "What does the woman suggest?", "opts": ["Reviewing an advertisement layout", "Seeking feedback from a boss", "Testing slogans with customers", "Launching a new line of merchandise"], "ans": 1, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Our company is releasing a new line of light bulbs next month. We've been assigned to create an advertising campaign slogan for it. Right now, I'm leaning towards the saying, \"leading the way,\" with the letters l, e, and d in bold to refer to our light-emitting diode products pictured in the ads.", "ko": "우리 회사는 다음 달에 새로운 백열전구 제품을 출시할 거예요. 우리가 그것을 위한 광고 캠페인의 선전 문구를 만드는 일을 맡았어요. 지금 저는 광고에서 묘사되는 우리의 발광 다이오드 제품들을 나타내기 위해 l, e, 그리고 d를 굵은 활자로 표시한 \"leading the way\"라는 문구로 마음이 기울고 있어요."}, {"sp": "W", "en": "It's short and clever, but I don't think it highlights our product's competitive attributes enough. Do you have any other ideas?", "ko": "그것은 짧고 기발하지만, 우리 제품의 경쟁력 있는 특징들을 충분히 강조하지 않는 것 같아요. 다른 아이디어가 있나요?"}, {"sp": "M", "en": "I also came up with the slogan \"bright lights, small impact\" because our lights have less of a negative effect on the environment than regular light bulbs do.", "ko": "우리 전등들이 보통 전구들보다 환경에 부정적인 영향을 적게 미치기 때문에 \"bright lights, small impact\"라는 선전 문구 또한 생각했어요."}, {"sp": "W", "en": "I think we should go with that slogan. Let's bring it up to our supervisor at the staff meeting later today and see what his opinion is.", "ko": "그 선전 문구로 해야 할 것 같아요. 오늘 늦게 있을 직원 회의에서 관리자에게 그것을 내놓고 그의 의견이 어떤지 보도록 하죠."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test03_53-55.mp3", "qs": [{"n": 53, "q": "What does the man give the woman?", "opts": ["A sporting event ticket", "A team uniform", "A purchase receipt", "A banner design"], "ans": 3, "ko": "남자는 여자에게 무엇을 주는가?"}, {"n": 54, "q": "According to the man, what happened last week?", "opts": ["A delivery was received.", "An event was canceled.", "An item was damaged.", "A structure was set up."], "ans": 2, "ko": "남자에 따르면, 지난주에 무슨 일이 일어났는가?"}, {"n": 55, "q": "What will the woman most likely do next?", "opts": ["Remove a price tag", "Perform a demonstration", "Repair some equipment", "Lead the man to a display"], "ans": 1, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Hi. The recreational baseball team that I play on needs a banner for an upcoming tournament. Here is what it should look like.", "ko": "안녕하세요. 제가 선수로 뛰는 오락 야구팀이 다가오는 경기를 위해 현수막이 필요해요. 그것이 어떻게 생겨야 하는지가 여기 있어요."}, {"sp": "W", "en": "Let's see . . . The Panthers? Wait, didn't I make a banner for your team a few months ago . . . one with a blue and green stripe along the bottom?", "ko": "어디 한번 봐요… The Panthers요? 잠시만요, 몇 달 전에 당신의 팀을 위해 제가 현수막을 만들지 않았나요… 파란색과 초록색 줄이 하단을 따라 있는 현수막이요?"}, {"sp": "M", "en": "Yes. But last week there was a storm, and the banner was pulled off the fence by the wind. It has a big tear in it now.", "ko": "네. 하지만 지난주에 폭풍우가 와서, 현수막이 바람 때문에 담에서 떨어졌어요. 지금 현수막에 큰 구멍이 있어요."}, {"sp": "W", "en": "Oh, what a shame. I can have a new one ready by Friday. But, um, before you leave . . . Why don't I show you how to securely attach a banner to a fence? That way you can avoid similar issues in the future.", "ko": "아, 그것 참 유감이네요. 금요일까지 새 현수막이 준비되도록 할 수 있어요. 그런데, 음, 당신이 떠나시기 전에… 현수막을 담에 어떻게 단단히 다는지 제가 보여드리는 것이 어떨까요? 그렇게 하면 당신은 앞으로 유사한 문제들을 피할 수 있어요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test03_56-58.mp3", "qs": [{"n": 56, "q": "What does the man say about the brochure?", "opts": ["It features some photographs.", "It needs a minor change.", "It will be unveiled online.", "It will be delivered tomorrow."], "ans": 1, "ko": "남자는 소책자에 관해 무엇을 말하는가?"}, {"n": 57, "q": "What does the woman offer to do?", "opts": ["Arrange an appointment", "Update some printed instructions", "Provide a paper copy", "Get supplies from her office"], "ans": 2, "ko": "여자는 무엇을 해주겠다고 제안하는가?"}, {"n": 58, "q": "What will the man probably do before lunch?", "opts": ["Add text to a brochure", "Register for a trade show", "Distribute some handouts", "See a physician"], "ans": 3, "ko": "남자는 점심 전에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Jennifer, I've reviewed the product brochure draft for the trade show. It looks good on the whole, but I think we should slightly increase the size of our logo. It's rather small compared to everything else, and I wanna make sure that it really stands out.", "ko": "Jennifer, 무역 박람회를 위한 제품 소책자 초안을 검토했어요. 대체로 괜찮은 것 같지만, 우리 로고의 크기를 약간 키워야 할 것 같아요. 다른 모든 것들에 비해 약간 작은데, 저는 로고가 확실히 눈에 띄게 하고 싶어요."}, {"sp": "W", "en": "Certainly, Mr. Harris. That shouldn't be difficult to fix. I can print out a copy of the updated brochure and bring it back to your office in about an hour. Is there anything else you want changed?", "ko": "그렇게 할게요, Mr. Harris. 그것은 고치기 어렵지 않을 거예요. 업데이트된 소책자의 사본 한 부를 출력해서 약 한 시간 후에 당신의 사무실로 다시 가져다드릴 수 있어요. 바뀌었으면 하는 다른 것이 또 있으신가요?"}, {"sp": "M", "en": "No, I think that's all. However, I have a doctor's appointment just before lunchtime, so leave the brochure with my assistant.", "ko": "아니요, 그게 다인 것 같아요. 하지만, 저는 점심시간 바로 전에 진료 예약이 있으니, 소책자는 제 비서에게 맡겨주세요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 호주식 발음 → 영국식 발음", "audio": "Test03_59-61.mp3", "qs": [{"n": 59, "q": "What will happen this Friday?", "opts": ["An art contest will begin.", "An auction will be hosted.", "An exhibition will be held.", "An establishment will close down."], "ans": 2, "ko": "이번 주 금요일에 무슨 일이 일어날 것인가?"}, {"n": 60, "q": "Why does the woman say, \"I'm working late on Friday\"?", "opts": ["To request an alternative", "To change a schedule", "To decline an invitation", "To cancel a plan"], "ans": 2, "ko": "여자는 왜 \"저는 금요일에 늦게까지 일할 거예요\"라고 말하는가?"}, {"n": 61, "q": "What is mentioned about Harris Kitchen?", "opts": ["It is close to a gallery.", "It is holding a promotion right now.", "It is busy on weekends.", "It is not able to accept reservations."], "ans": 0, "ko": "Harris Kitchen에 관해 무엇이 언급되는가?"}], "script": [{"sp": "M1", "en": "Do you wanna join me this Friday for an event? Gallery Blue is holding a show of the latest work of sculptor Kerry Marx then.", "ko": "이번 주 금요일 행사에 저와 함께 가길 원하시나요? Blue 미술관이 그때 조각가 Kerry Marx의 최신 작품 전시를 열 거예요."}, {"sp": "M2", "en": "Sure. I'm quite fond of her sculptures. When should we head there?", "ko": "물론이에요. 전 그녀의 조각품들을 정말 좋아해요. 우리가 언제 그곳에 가야 할까요?"}, {"sp": "M1", "en": "How does 7 P.M. sound? If you want, we can grab dinner beforehand as well.", "ko": "오후 7시는 어떠세요? 원하신다면, 우리는 미리 저녁도 먹을 수 있어요."}, {"sp": "M2", "en": "That sounds good. Ellen, would you like to come, too?", "ko": "좋아요. Ellen, 당신도 가실래요?"}, {"sp": "W", "en": "I'm working late on Friday. However, I have a gift certificate for Harris Kitchen that I can give you. It expires on Saturday, so someone should use it.", "ko": "저는 금요일에 늦게까지 일할 거예요. 하지만, 여러분께 드릴 수 있는 Harris Kitchen의 상품권이 있어요. 그건 토요일에 만료되어서, 누군가는 그것을 써야 해요."}, {"sp": "M1", "en": "That'd be great, Ellen. Harris Kitchen is in the vicinity of the gallery.", "ko": "그거 좋겠네요, Ellen. Harris Kitchen은 미술관 근처에 있어요."}, {"sp": "W", "en": "Wonderful. Well, I'll get you the certificate tomorrow.", "ko": "훌륭하네요. 음, 내일 상품권을 가져다드릴게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test03_62-64.mp3", "qs": [{"n": 62, "q": "Where do the speakers most likely work?", "opts": ["At a conference center", "At a financial institution", "At a government office", "At a publishing firm"], "ans": 1, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 63, "q": "What does the man mention about Donald Sawyer?", "opts": ["He is meeting a client.", "He is a successful author.", "He is a new team manager.", "He is driving to a venue."], "ans": 1, "ko": "남자는 Donald Sawyer에 관해 무엇을 언급하는가?"}, {"n": 64, "q": "Look at the graphic. Which room will the woman most likely book?", "opts": ["Room 101", "Room 102", "Room 202", "Room 203"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어떤 방을 예약할 것 같은가?"}], "script": [{"sp": "M", "en": "Hi, Sarah. Our team leader mentioned that you are organizing the retirement planning seminar for our bank's clients. How's it going?", "ko": "안녕하세요, Sarah. 당신이 우리 은행의 고객들을 위한 은퇴 계획 세미나를 준비하신다고 우리 팀장님이 말씀하셨어요. 어떻게 되어가고 있나요?"}, {"sp": "W", "en": "Good. Donald Sawyer just confirmed that he will give a presentation.", "ko": "좋아요. Donald Sawyer는 방금 그가 발표를 하겠다는 것을 확정했어요."}, {"sp": "M", "en": "That's great. His book on investing was a best-seller. Um, have you selected a venue?", "ko": "잘됐네요. 투자에 관한 그의 책이 베스트셀러였잖아요. 음, 장소는 선택하셨나요?"}, {"sp": "W", "en": "I've decided on the Bridgeport Convention Hall. It has two meeting rooms large enough to accommodate the 180 people who I estimate will sign up. I just need to choose between a theater or classroom layout.", "ko": "Bridgeport 컨벤션 홀로 결정했어요. 그곳에는 등록할 것으로 예상하는 180명을 수용할 만큼 충분히 큰 회의실이 두 개 있어요. 저는 극장 배치로 할 것인지 강의실 배치로 할 것인지만 선택하면 돼요."}, {"sp": "M", "en": "The classroom layout would be best, in my opinion. Having tables would make it easier for attendees to take notes.", "ko": "제 생각에는, 강의실 배치가 가장 좋을 것 같아요. 테이블이 있는 것이 참석자들이 메모를 하기가 더 쉬울 거예요."}], "gimg": "hk2_t3_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test03_65-67.mp3", "qs": [{"n": 65, "q": "What did the woman do last Thursday?", "opts": ["Corrected a fiscal report", "Started a new position", "Sent in a record of hours", "Distributed an office notice"], "ans": 2, "ko": "여자는 지난 목요일에 무엇을 했는가?"}, {"n": 66, "q": "What problem does the man mention?", "opts": ["An overtime request was denied.", "A monthly amount was exceeded.", "An official document was not submitted.", "An accounting report was not revised."], "ans": 1, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 67, "q": "Look at the graphic. Which extension will the woman probably call?", "opts": ["2341", "2502", "2008", "2729"], "ans": 0, "ko": "시각 자료를 보시오. 여자는 어느 내선 번호로 전화할 것 같은가?"}], "script": [{"sp": "M", "en": "Marie, an error was discovered on the time sheet you submitted last Thursday.", "ko": "Marie, 당신이 지난 목요일에 제출했던 근무 시간 기록표에서 오류가 발견되었어요."}, {"sp": "W", "en": "Really? What seems to be the issue?", "ko": "정말요? 무엇이 문제인 것 같나요?"}, {"sp": "M", "en": "Wendy from the accounting department says you entered more than the maximum allowed hours per month.", "ko": "회계부의 Wendy가 당신이 월 최대 허용 시간보다 더 많이 입력했다고 해요."}, {"sp": "W", "en": "How odd. I'm fairly sure I wrote 200 hours on the sheet, but maybe I'm wrong.", "ko": "이상하네요. 시트에 200시간을 썼다고 꽤 확신하는데, 아마 제가 틀렸나 봐요."}, {"sp": "M", "en": "Perhaps. Anyway, you'll have to submit a revised timecard. Also, Wendy usually handles such information, but she and Robert are on a business trip together this week. So you should call the human resources manager to find out whom to submit the document to.", "ko": "아마도요. 어쨌든, 수정된 근무 시간 기록표를 제출해야 할 거예요. 또한, 보통은 Wendy가 이러한 자료를 다루지만, 그녀와 Robert가 이번 주에 함께 출장 중이에요. 그래서 그 문서를 누구에게 제출해야 하는지 알아보기 위해서는 인사 부장에게 전화하셔야 해요."}, {"sp": "W", "en": "All right. And sorry about the problem. I'll be sure not to let it happen again.", "ko": "알겠어요. 그리고 이 문제에 대해 사과드려요. 다시 이런 일이 일어나지 않도록 확실히 할게요."}], "gimg": "hk2_t3_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test03_68-70.mp3", "qs": [{"n": 68, "q": "Why does the man want to hold a meeting?", "opts": ["To introduce new crew members", "To discuss a funding shortage", "To announce a business partnership", "To go over a future project"], "ans": 3, "ko": "남자는 왜 회의를 열기 원하는가?"}, {"n": 69, "q": "Look at the graphic. Which topic will the man address?", "opts": ["Communication", "Professionalism", "Punctuality", "Cleanliness"], "ans": 1, "ko": "시각 자료를 보시오. 남자는 어느 주제를 다룰 것인가?"}, {"n": 70, "q": "What will the woman probably do in the afternoon?", "opts": ["Draft a client questionnaire", "Post a message on a Web site", "Review additional comment cards", "Schedule an appointment with a client"], "ans": 1, "ko": "여자는 오후에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Later this afternoon, I want our crew leaders to get together to be briefed on Fillmore Stadium, which is the next building our firm is going to renovate.", "ko": "오늘 오후 늦게, 우리 회사가 개조할 다음 건물인 Fillmore 경기장에 대해 간단히 설명을 듣도록 팀장들이 모였으면 좋겠어요."}, {"sp": "W", "en": "Some of the crew leaders have been asking about when work on the stadium is set to begin, so they'll be eager to learn more.", "ko": "팀장들 중 몇몇이 그 경기장에 대한 작업이 언제 시작될 것인지 물어왔기 때문에, 그들은 더 알고 싶어 할 거예요."}, {"sp": "M", "en": "Good. I'm also gonna bring up comments a recent client shared with us. Aside from cleanliness—which I've already talked about to supervisors—her feedback highlights a less-than-ideal aspect of our service that I need to talk about.", "ko": "좋아요. 저는 또한 최근 한 고객이 저희와 공유한 의견들을 내놓을 거예요. 제가 이미 관리자들에게 이야기한 청결을 제외하고, 그녀의 의견은 우리 서비스의 이상적이지 못한 면을 강조했는데 이에 대해 제가 이야기해야 해요."}, {"sp": "W", "en": "OK. Well, I'll post a memo about it this afternoon on our online board.", "ko": "알겠어요. 음, 제가 오늘 오후에 우리 온라인 게시판에 이것에 관한 회람을 게시할게요."}, {"sp": "M", "en": "Thanks. Oh . . . and please schedule the meeting for 4:15 P.M.", "ko": "고마워요. 아… 그리고 회의는 오후 4시 15분으로 잡아주세요."}], "gimg": "hk2_t3_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test03_71-73.mp3", "qs": [{"n": 71, "q": "Why is traffic heavy on the Bayport Bridge?", "opts": ["An accident has occurred.", "An entrance has been closed.", "Repair work is being performed.", "An expressway is inaccessible."], "ans": 0, "ko": "Bayport 다리의 교통은 왜 혼잡한가?"}, {"n": 72, "q": "When will traffic in the city return to normal?", "opts": ["In 20 minutes", "In 40 minutes", "In one hour", "In two hours"], "ans": 3, "ko": "도시의 교통은 언제 정상으로 돌아갈 것인가?"}, {"n": 73, "q": "What does the speaker suggest?", "opts": ["Contacting a hotline", "Taking an alternative route", "Avoiding the downtown area", "Using public transportation"], "ans": 3, "ko": "화자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "This is Katie Jackson on T T Radio 96.1 FM, and it's time for your morning traffic report. Drivers heading into the downtown area should take note that there is heavy traffic on the Bayport Bridge. There was a collision involving three cars approximately 20 minutes ago at the south entrance to the bridge, resulting in the closure of two of the northbound lanes. Elsewhere, workers are conducting routine repair work on the Harborview Expressway, which is the other main road into the city's business district. Motorists should expect delays of up to 40 minutes. Clearing these backups will take about two hours. In the meantime, it would be best to commute by subway this morning.", "ko": "저는 96.1 FM T T Radio의 Katie Jackson이며, 지금은 아침 교통방송 시간입니다. 도심 지역으로 향하는 운전자들은 Bayport 다리의 교통이 혼잡하다는 것에 주목하셔야 합니다. 대략 20분 전쯤에 다리의 남쪽 입구에서 세 대의 차량이 연루된 충돌이 있었으며, 이것이 북쪽으로 향하는 두 개 차선의 봉쇄를 야기했습니다. 다른 곳에서는, 시의 상업 지구로 들어가는 또 다른 주요 도로인 Harborview 고속도로에서 인부들이 정기 보수 공사를 진행하고 있습니다. 운전자들은 40분까지의 지연을 예상하셔야 합니다. 이 정체들이 다시 원활해지는 데에는 두 시간 정도 걸릴 것입니다. 그때까지, 오늘 아침에는 지하철로 통근하시는 것이 가장 좋을 것 같습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test03_74-76.mp3", "qs": [{"n": 74, "q": "Who most likely is the speaker?", "opts": ["An office assistant", "A computer repairperson", "A course instructor", "A career consultant"], "ans": 2, "ko": "화자는 누구인 것 같은가?"}, {"n": 75, "q": "What benefit does the speaker mention?", "opts": ["A complimentary textbook", "A free consultation", "A discounted membership", "An inexpensive software program"], "ans": 1, "ko": "화자는 어떤 혜택을 언급하는가?"}, {"n": 76, "q": "What does the speaker request that listeners do?", "opts": ["Write down their contact information", "Create a system account", "Apply for some positions", "Sign in to a computer network"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "W", "en": "Welcome, everyone, to this orientation session for our institute's certification course for Web software developers. I'm Holly Bender, your teacher for the next few weeks. Before we begin, I'd like to share some news with you. When your course is completed, you'll each have a chance to consult with a career consultant to seek professional advice at no additional cost. It'll be a great benefit to you all, so I hope you make the most of it. Now, let's go ahead and start our first session. You should log on to our training system by entering the username and password indicated on your name tags.", "ko": "웹 소프트웨어 개발자들을 위한 저희 기관의 자격증 강좌 오리엔테이션 시간에 오신 여러분을 환영합니다. 저는 앞으로 몇 주 동안 여러분의 강사인 Holly Bender입니다. 시작하기 전에, 저는 여러분과 몇 가지 소식을 나누고 싶습니다. 강좌가 끝나면, 여러분은 추가 비용 없이 전문적인 조언을 구하기 위해 취업 컨설턴트와 상담할 기회를 각자 가지게 될 것입니다. 그것은 여러분 모두에게 굉장한 혜택일 것이므로, 그것을 최대한 활용하시길 바랍니다. 이제, 나아가서 우리의 첫 번째 수업을 시작합시다. 여러분은 이름표에 표시된 사용자명과 비밀번호를 입력함으로써 교육 시스템에 로그인하셔야 합니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test03_77-79.mp3", "qs": [{"n": 77, "q": "Why is the speaker calling?", "opts": ["To explain a new procedure", "To check the status of an assignment", "To request some information", "To inquire about a quotation"], "ans": 2, "ko": "화자는 왜 전화를 하고 있는가?"}, {"n": 78, "q": "What is mentioned about Ms. Hollandale?", "opts": ["She works as a photographer.", "She forgot to respond to a voice mail.", "She filled out an insurance form.", "She offers personal tax advice."], "ans": 0, "ko": "Ms. Hollandale에 관해 무엇이 언급되는가?"}, {"n": 79, "q": "What is the speaker currently unable to do?", "opts": ["Make a final payment", "Postpone an appointment", "Proofread some files", "Submit some paperwork"], "ans": 3, "ko": "화자는 현재 무엇을 할 수 없는가?"}], "script": [{"sp": "M", "en": "Hello, Ms. Hollandale. This is Shawn Reardon, your tax adviser, calling about your annual tax return. I was just going through the documents you provided, and I realized that some figures are missing. Specifically, I don't have any information about the income you earned as a freelance photographer. These earnings obviously have to be included in your tax return. Could you please e-mail me copies of the receipts that you issued to your clients last year? I won't be able to file your state and federal tax forms until you've done this. Thank you.", "ko": "안녕하세요, Ms. Hollandale. 저는 귀하의 세금 자문가 Shawn Reardon이며, 귀하의 연간 소득 신고서에 관해 전화드립니다. 귀하께서 주셨던 서류를 방금 살펴보고 있었는데, 몇몇 수치가 누락되어 있음을 알아차렸습니다. 구체적으로 말씀드리면, 저는 귀하께서 프리랜서 사진작가로 벌어들인 소득에 대한 어떤 자료도 가지고 있지 않습니다. 이 수입은 분명히 귀하의 소득 신고서에 포함되어 있어야 합니다. 귀하께서 작년에 고객들에게 발부한 영수증들의 사본을 제게 이메일로 보내주시겠습니까? 이것을 해주신 후에야 제가 귀하의 주 정부 및 연방 정부 세금 신고서를 제출할 수 있을 것입니다. 감사합니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test03_80-82.mp3", "qs": [{"n": 80, "q": "What is being advertised?", "opts": ["A fitness center", "A bicycle repair shop", "A sporting goods store", "An athletic association"], "ans": 2, "ko": "무엇이 광고되고 있는가?"}, {"n": 81, "q": "Why does the speaker say, \"our in-store staff will be happy to assist you\"?", "opts": ["To recommend a rental service", "To encourage returns", "To highlight a limited-time offer", "To promote membership options"], "ans": 1, "ko": "화자는 왜 \"저희 매장 내의 직원들이 고객님을 기꺼이 도울 것입니다\"라고 말하는가?"}, {"n": 82, "q": "What does the speaker say is available for rent?", "opts": ["Some footwear", "Some boats", "Safety gear", "Camping tents"], "ans": 1, "ko": "화자는 무엇이 대여 가능하다고 말하는가?"}], "script": [{"sp": "M", "en": "Do you want the latest sports equipment at unbeatable prices? If so, come to Flynn Recreation, where we carry Edmonton's widest selection of athletic merchandise! No matter what activity you're interested in, we're confident that we'll have the proper gear in stock. Moreover, if you're unhappy with something you purchased, no problem. So long as the item is not damaged, our in-store staff will be happy to assist you. We're now also offering equipment rentals. With this new service, customers can use our brand-name kayaks, mountain bikes, and snowboards for seven days by paying a small fee. It's perfect for overnight and weekend camping trips. Visit us at 518 Baker Avenue to learn more!", "ko": "더 이상 좋을 수 없는 가격의 최신 스포츠 장비를 원하시나요? 그렇다면, 에드먼턴에서 가장 다양한 운동용품을 취급하는 Flynn Recreation으로 오세요! 고객님께서 어떤 활동에 관심이 있으시든, 저희에게 적합한 장비가 비축되어 있을 것이라고 확신합니다. 게다가, 만약 고객님께서 구매하신 것에 만족하지 않으셔도, 문제없습니다. 그 품목이 손상되지만 않았다면, 저희 매장 내의 직원들이 고객님을 기꺼이 도울 것입니다. 저희는 이제 장비 대여도 제공합니다. 이 새로운 서비스로, 적은 비용만 지불함으로써 고객님께서는 유명 상표의 카약, 산악자전거, 그리고 스노보드를 7일 동안 이용하실 수 있습니다. 이는 야간 및 주말 캠핑 여행에 완벽합니다. 더 알아보시려면 Baker가 518번지로 방문하세요!"}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test03_83-85.mp3", "qs": [{"n": 83, "q": "What is the purpose of the talk?", "opts": ["To promote a waste management system", "To announce a development plan", "To ask listeners to make donations", "To provide instructions to volunteers"], "ans": 3, "ko": "담화의 목적은 무엇인가?"}, {"n": 84, "q": "What does the speaker mean when she says, \"the park is quite large\"?", "opts": ["An event will have sufficient space.", "A task will take a while to complete.", "A tour will cover a sizeable area.", "A lot of flowers need to be planted."], "ans": 1, "ko": "화자는 \"공원이 상당히 큽니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 85, "q": "What does the speaker offer to do?", "opts": ["Show visitors around a site", "Load equipment into a van", "Provide gear to participants", "Discuss a revised work schedule"], "ans": 2, "ko": "화자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "I want to express how much we at Green Renewal appreciate all of you donating your time and energy to help us remove waste from the grounds of Pine Park. Your task this morning is to walk around the park and pick up the litter that accumulated throughout the winter. You'll be doing this in groups of four, each of which will be assigned to a specific area. We'd better get started right away. As you can see, the park is quite large. If you all follow me to the van parked next to that row of flowers, I'll give the necessary equipment to everyone.", "ko": "저희 Green Renewal은 여러분 모두가 시간과 에너지를 바쳐서 Pine 공원 운동장의 쓰레기를 치우도록 도와주시는 것에 대해 얼마나 감사하게 생각하는지 말씀드리고 싶습니다. 오늘 아침 여러분의 업무는 공원 주위를 돌아다니면서 겨울 동안 쌓인 쓰레기를 줍는 것입니다. 여러분은 4명이 한 조로 이것을 하게 될 것이며, 각 조는 특정 구역을 배정받을 것입니다. 우리는 지금 바로 시작하는 것이 좋을 것 같습니다. 보시다시피, 공원이 상당히 큽니다. 여러분 모두 저기 줄지어 있는 꽃들 옆에 주차된 승합차로 저를 따라오시면, 필요한 장비를 모두에게 제공해 드리겠습니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test03_86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker say about the Corbyn Film Festival?", "opts": ["It is going to be held over four days.", "It focuses on a specific genre.", "It has been widely publicized.", "It has never been hosted before."], "ans": 3, "ko": "화자는 Corbyn 영화제에 관해 무엇을 말하는가?"}, {"n": 87, "q": "According to the speaker, what will take place at 8 P.M.?", "opts": ["A documentary film screening", "A question and answer session", "A private party", "An award ceremony"], "ans": 1, "ko": "화자에 따르면, 오후 8시에 무엇이 열릴 것인가?"}, {"n": 88, "q": "Why should listeners visit a lobby area?", "opts": ["To get some refreshments", "To purchase admission tickets", "To see a revised schedule", "To review movie options"], "ans": 0, "ko": "청자들은 왜 로비 구역을 방문해야 하는가?"}], "script": [{"sp": "M", "en": "Thank you for attending the Corbyn Film Festival. Although this is our organization's first festival, we hope to hold many more in the future. Over the course of the next three days, 20 films from around the world will be screened, including ones that have received recognition at other major festivals. Moreover, we are pleased to inform everyone that we will be joined by legendary director Luke Norris. Mr. Norris, whose documentary White Lines will air this evening, has graciously offered to respond to questions during a meet and greet at 8 P.M. And, as a final reminder, feel free to head to the lobby at any point to buy drinks and snacks.", "ko": "Corbyn 영화제에 참석해주셔서 감사합니다. 이번이 우리 단체의 최초의 축제이지만, 저희는 미래에 더 많이 개최하기를 바랍니다. 다음 3일 동안, 다른 주요 영화제들에서 인정을 받았던 영화들을 포함하여, 전 세계 20편의 영화들이 상영될 것입니다. 게다가, 전설적인 감독 Luke Norris가 저희와 함께할 것이라는 것을 여러분께 알려드리게 되어 기쁩니다. 오늘 저녁에 방영될 다큐멘터리 White Lines의 감독인 Mr. Norris는, 감사하게도 오후 8시에 팬미팅 중 질문들에 응답하기로 하였습니다. 그리고 마지막으로 말씀드리자면, 음료와 간식을 사기 위해 언제든 로비로 오십시오."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test03_89-91.mp3", "qs": [{"n": 89, "q": "Who most likely is Oscar Juan?", "opts": ["A curator", "An artist", "A critic", "A magazine editor"], "ans": 1, "ko": "Oscar Juan은 누구인 것 같은가?"}, {"n": 90, "q": "When is the exhibit scheduled to begin?", "opts": ["September 27", "October 1", "October 3", "October 14"], "ans": 2, "ko": "전시회는 언제 시작될 예정인가?"}, {"n": 91, "q": "What will the listeners most likely do next?", "opts": ["Arrange an exhibit", "Bid on some paintings", "Watch a presentation", "Go to another center"], "ans": 2, "ko": "청자들은 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "As you may have heard, our art center is planning to display some works by Oscar Juan. I expect the show will attract many potential buyers as well as some media attention. This is because Mr. Juan will be featured in an issue of a national art magazine that comes out on September 27, which is roughly one week before the exhibit here will begin. Um . . . the exhibition will run from October 3 to October 14. As this will be our center's most important exhibit yet, it is crucial that everything goes smoothly. Our curator will now show us some slides of the paintings we will be displaying and provide some background information on each. This will hopefully give us some ideas about how to organize the exhibit.", "ko": "여러분이 들으셨을 수도 있지만, 우리 예술 센터에서 Oscar Juan의 몇몇 작품들을 전시할 계획입니다. 저는 이 전시회가 언론의 주목뿐만 아니라 많은 잠재적 구매자들을 끌어모을 것이라고 기대합니다. 이는 Mr. Juan이 9월 27일에 출간되는 국내 예술 잡지 발행물에서 특집으로 다뤄질 것이기 때문인데, 이것은 이곳 전시회가 시작되기 대략 일주일 전입니다. 음… 전시회는 10월 3일부터 10월 14일까지 진행될 것입니다. 이것이 우리 센터의 가장 중요한 전시회일 것이기 때문에, 모든 것이 순조롭게 진행되는 것이 중요합니다. 이제 우리 큐레이터가 우리가 전시하게 될 그림들의 슬라이드 몇 장을 보여주고 각각에 대한 배경 정보를 제공할 것입니다. 이것이 우리에게 전시회를 어떻게 준비할지에 대한 몇 가지 아이디어를 제공해주기를 바랍니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test03_92-94.mp3", "qs": [{"n": 92, "q": "Why does the speaker apologize?", "opts": ["She is behind schedule.", "She forgot to send out an announcement.", "A room is too small.", "A class will end earlier than expected."], "ans": 0, "ko": "화자는 왜 사과하는가?"}, {"n": 93, "q": "What will listeners have a chance to make?", "opts": ["A button-up shirt", "A suit jacket", "Some pants", "Some socks"], "ans": 1, "ko": "청자들은 무엇을 만들 기회를 가질 것인가?"}, {"n": 94, "q": "What does the speaker mean when she says, \"the fabric is located in the back cabinet\"?", "opts": ["An order arrived on time.", "An organization accepted a donation.", "A suggestion has been received.", "An issue has been addressed."], "ans": 3, "ko": "화자는 \"천은 뒤쪽 보관함에 있습니다\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "W", "en": "Welcome to this advanced sewing community education course. First, let me apologize for not showing up on time. I realized I left my class notes at my house while driving here, so I had to go home and get them. I promise that won't happen again. Now, this course will be held over a three-week period. During that time, you will all have a chance to make either a dress or a suit jacket. It should be a lot of fun! Oh . . . And we previously kept fabric in the small closet near the door. However, that storage space was too small to hold everything. Now, the fabric is located in the back cabinet.", "ko": "상급 바느질 주민 교육 과정에 오신 것을 환영합니다. 먼저, 제시간에 오지 못한 것에 대해 사과드립니다. 제가 여기로 운전해 오는 동안, 집에 제 수업 노트를 두고 왔음을 알아차려서, 집으로 가서 그것들을 가져와야 했습니다. 다시는 이 일이 일어나지 않을 것임을 약속드립니다. 자, 이 과정은 3주 동안 열릴 것입니다. 그 시간 동안, 여러분은 모두 드레스 또는 정장 재킷을 만들 기회를 가질 것입니다. 그건 정말 재미있을 거예요! 아… 그리고 저희는 이전에는 문 근처의 작은 옷장에 천을 보관했습니다. 하지만, 그 저장 공간은 너무 작아서 모든 것을 넣어둘 수 없었습니다. 이제, 천은 뒤쪽 보관함에 있습니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test03_95-97.mp3", "qs": [{"n": 95, "q": "Where does the speaker work?", "opts": ["At an airport", "At a hotel", "At a tour company", "At a car rental agency"], "ans": 1, "ko": "화자는 어디에서 일하는가?"}, {"n": 96, "q": "Look at the graphic. Which exit does the shuttle bus stop at?", "opts": ["Exit 1", "Exit 2", "Exit 3", "Exit 4"], "ans": 2, "ko": "시각 자료를 보시오. 셔틀버스는 어느 출구에 정차하는가?"}, {"n": 97, "q": "What does the speaker offer to do?", "opts": ["Fulfill a customer's special request", "Explain an ongoing renovation project", "Send a reservation confirmation by e-mail", "Provide a complimentary upgrade"], "ans": 3, "ko": "화자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Hello, Mr. Chen. This is Karen calling from the Emerald Lodge with regards to your interest in a recent inquiry. In your e-mail, you inquired about arranging transportation from the airport to our lodge. We have a shuttle bus that picks up passengers outside of the arrivals terminal. It stops directly across from the taxi stand. Moreover, you requested a room overlooking the pool area. Unfortunately, that entire wing will be unavailable to guests on the night you will be staying with us due to ongoing renovations. However, I can book you a larger room with a view of the ocean at no additional charge. Please contact me at 555-4024 to let me know whether that would be suitable.", "ko": "안녕하세요, Mr. Chen. 저는 최근 문의에서 표하신 고객님의 관심에 관해 Emerald 호텔에서 전화드리는 Karen입니다. 고객님의 이메일에서, 고객님께서는 공항에서부터 저희 호텔까지의 교통편을 마련하는 것에 대해 문의하셨습니다. 저희는 도착 터미널 밖에서 승객들을 태우는 셔틀버스가 있습니다. 이 버스는 택시 승강장 바로 맞은편에서 정차합니다. 더불어, 고객님께서는 수영장이 내려다보이는 객실을 요청하셨습니다. 유감스럽게도, 진행 중인 수리로 인해 그 동 전체는 고객님께서 저희와 함께 지내실 그 밤에 이용하실 수 없을 것입니다. 하지만, 고객님께 바다가 보이는 더 큰 객실을 추가 요금 없이 예약해 드릴 수 있습니다. 이것이 적절하실지 555-4024로 제게 연락하시어 알려주십시오."}], "gimg": "hk2_t3_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "캐나다식 발음", "audio": "Test03_98-100.mp3", "qs": [{"n": 98, "q": "Why did the listener travel to London?", "opts": ["To conduct a consumer survey", "To attend a technology fair", "To open a branch office", "To observe a product test"], "ans": 1, "ko": "청자는 왜 런던에 갔는가?"}, {"n": 99, "q": "Look at the graphic. Which transaction does the speaker want to discuss?", "opts": ["00320", "00321", "00322", "00323"], "ans": 1, "ko": "시각 자료를 보시오. 화자는 어떤 거래에 관해 논의하고 싶어 하는가?"}, {"n": 100, "q": "What is the listener asked to do?", "opts": ["Visit an office", "Confirm a purchase", "Send receipts", "Call a supervisor"], "ans": 0, "ko": "청자는 무엇을 하도록 요청받는가?"}], "script": [{"sp": "M", "en": "Good morning, Ms. Harkins. I'm Owen Connor from the accounting department. I need to speak to you about the charges you made to your company credit card in London last month. I believe you were participating in the product launch at the Riverside Electronics Exhibition. I received your e-mail with the scans of the statements for your airfare, meals, and accommodations, but there's an issue with one of the transactions. It is company policy that staff can only charge a maximum of £30 per meal. It would probably be best if we talked about this in person rather than over the phone. Why don't you stop by my office tomorrow morning? Say around eleven? Thanks.", "ko": "안녕하세요, Ms. Harkins. 저는 회계부의 Owen Connor입니다. 지난달 런던에서 당신이 법인 카드로 결제한 비용에 관해 이야기할 필요가 있습니다. 당신은 Riverside 전자 제품 박람회의 제품 출시 행사에 참석하셨던 것이라 생각합니다. 저는 항공 요금과 식비, 그리고 숙박비 명세서의 스캔본을 포함한 당신의 이메일을 받았습니다만, 거래들 중 한 건에 문제가 있습니다. 직원들은 한 끼에 최대 30파운드까지만 청구할 수 있다는 것이 회사 방침입니다. 저는 우리가 전화로 이야기하는 것보다 직접 만나서 이것에 관해 이야기하는 것이 가장 좋을 것 같습니다. 내일 오전에 제 사무실에 들르는 게 어떠신가요? 11시쯤으로 할까요? 감사합니다."}], "gimg": "hk2_t3_g98.jpg"}]};
